5. /// <summary>
6. /// Defines the contract for formatting date/time humanization output
7. /// in a locale-specific manner.
8. /// </summary>
9. public interface IFormatter
10. {
11.     /// <summary>Formats a "just now" reference.</summary>
12.     string DateHumanize_Now();
13. 
14.     /// <summary>Formats a "never" reference.</summary>
15.     string DateHumanize_Never();
16. 
17.     /// <summary>Formats a time unit reference (e.g., "2 hours ago").</summary>
18.     string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false);
19. }
20. 
21. /// <summary>
22. /// Defines the contract for ordinalizing numbers in a locale-specific manner.
23. /// </summary>
24. public interface IOrdinalizer
25. {
26.     /// <summary>
27.     /// Converts a number to its ordinal string representation (e.g., 1 → "1st").
28.     /// </summary>
29.     string Convert(int number, string numberString);
30. }
31. 
32. /// <summary>
33. /// Defines the contract for providing date-to-ordinal-words conversion.
34. /// </summary>
35. public interface IDateToOrdinalWordsConverter
36. {
37.     /// <summary>Converts a date to its ordinal words representation.</summary>
38.     string Convert(DateTime date);
39. }
40. 
41. /// <summary>
42. /// Default implementation of <see cref="IFormatter"/> providing English date/time formatting.
43. /// </summary>
44. public sealed class DefaultFormatter : IFormatter
45. {
46.     /// <inheritdoc />
47.     public string DateHumanize_Now() => "now";
48. 
49.     /// <inheritdoc />
50.     public string DateHumanize_Never() => "never";
51. 
52.     /// <inheritdoc />
53.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
54.     {
55.         var unit = GetUnitName(timeUnit, count != 1);
56.         return toWords ? $"{NumberToWords(count)} {unit}" : $"{count} {unit}";
57.     }
58. 
59.     private static string GetUnitName(TimeUnit timeUnit, bool plural) =>
60.         (timeUnit, plural) switch
61.         {
62.             (TimeUnit.Second, false) => "second",
63.             (TimeUnit.Second, true) => "seconds",
64.             (TimeUnit.Minute, false) => "minute",
65.             (TimeUnit.Minute, true) => "minutes",
66.             (TimeUnit.Hour, false) => "hour",
67.             (TimeUnit.Hour, true) => "hours",
68.             (TimeUnit.Day, false) => "day",
69.             (TimeUnit.Day, true) => "days",
70.             (TimeUnit.Month, false) => "month",
71.             (TimeUnit.Month, true) => "months",
72.             (TimeUnit.Year, false) => "year",
73.             (TimeUnit.Year, true) => "years",
74.             _ => plural
75.                 ? timeUnit.ToString().ToLowerInvariant() + "s"
76.                 : timeUnit.ToString().ToLowerInvariant()
77.         };
78. 
79.     private static string NumberToWords(int number) =>
80.         number switch
81.         {
82.             1 => "one",
83.             2 => "two",
84.             3 => "three",
85.             _ => number.ToString()
86.         };
87. }
88. 
89. /// <summary>
90. /// German-specific formatter providing localized date/time humanization.
91. /// </summary>
92. public sealed class GermanFormatter : IFormatter
93. {
94.     /// <inheritdoc />
95.     public string DateHumanize_Now() => "jetzt";
96. 
97.     /// <inheritdoc />
98.     public string DateHumanize_Never() => "nie";
