 {
     /// <summary>Converts a date to its ordinal words representation.</summary>
     string Convert(DateTime date);
 }

 /// <summary>
 /// Default implementation of <see cref="IFormatter"/> providing English date/time formatting.
 /// </summary>
 public sealed class DefaultFormatter : IFormatter
 {
     /// <inheritdoc />
     public string DateHumanize_Now() => "now";

     /// <inheritdoc />
     public string DateHumanize_Never() => "never";

     /// <inheritdoc />
     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
     {
         var unit = GetUnitName(timeUnit, count != 1);
         return toWords ? $"{NumberToWords(count)} {unit}" : $"{count} {unit}";
     }

     private static string GetUnitName(TimeUnit timeUnit, bool plural) =>
         (timeUnit, plural) switch
         {
             (TimeUnit.Second, false) => "second",
             (TimeUnit.Second, true) => "seconds",
             (TimeUnit.Minute, false) => "minute",
             (TimeUnit.Minute, true) => "minutes",
             (TimeUnit.Hour, false) => "hour",
             (TimeUnit.Hour, true) => "hours",
             (TimeUnit.Day, false) => "day",
             (TimeUnit.Day, true) => "days",
             (TimeUnit.Month, false) => "month",
             (TimeUnit.Month, true) => "months",
             (TimeUnit.Year, false) => "year",
             (TimeUnit.Year, true) => "years",
             _ => plural
                 ? timeUnit.ToString().ToLowerInvariant() + "s"
                 : timeUnit.ToString().ToLowerInvariant()
         };

     private static string NumberToWords(int number) =>
         number switch
         {
             1 => "one",
             2 => "two",
             3 => "three",
             _ => number.ToString()
         };
 }

